import pytest

# Assuming the function is imported from your module, e.g.:
# from your_module import max_subarray_sum

def max_subarray_sum(arr: list) -> int:
    if not arr:
        return 0
    max_sum = current = arr[0]
    for num in arr[1:]:
        current = max(num, current + num)
        max_sum = max(max_sum, current)
    return max_sum


class TestMaxSubarraySum:
    # ---- Happy paths ----

    def test_happy_path_mixed_integers(self):
        # Classic example: max subarray is [4, -1, 2, 1] => 6
        assert max_subarray_sum([-2, 1, -3, 4, -1, 2, 1, -5, 4]) == 6

    def test_happy_path_all_positive(self):
        assert max_subarray_sum([1, 2, 3, 4]) == 10

    def test_happy_path_all_negative(self):
        # Max subarray is the single largest element (-1)
        assert max_subarray_sum([-8, -3, -6, -2, -5, -4, -1]) == -1

    def test_happy_path_single_element(self):
        assert max_subarray_sum([7]) == 7

    def test_happy_path_max_subarray_at_start(self):
        # Best is prefix [1, 2, 3] => 6
        assert max_subarray_sum([1, 2, 3, -10, 5]) == 6

    def test_happy_path_max_subarray_in_middle(self):
        # Best is middle [-2, 5, -1, 2, -1] => 3
        assert max_subarray_sum([4, -1, -2, 5, -1, 2, -1, -5]) == 3

    def test_happy_path_max_subarray_at_end(self):
        # Best is suffix [3, 4, 2] => 9
        assert max_subarray_sum([-6, -1, 3, 4, 2]) == 9

    def test_happy_path_with_zeros(self):
        # Best can be [0, 0] => 0 or [1, 0, -1, 0] => 0; overall max is 0
        assert max_subarray_sum([0, -1, 0, -2, 0]) == 0

    # ---- Edge cases ----

    def test_edge_case_empty_list(self):
        assert max_subarray_sum([]) == 0

    def test_edge_case_contains_large_values(self):
        # Check it handles large magnitude integers correctly
        assert max_subarray_sum([10**12, -(10**12) + 5, 5]) == 10

    # ---- Error cases ----

    def test_error_case_none_input(self):
        # Function expects a list; passing None should raise TypeError because `if not arr:` is fine,
        # but later iterating would fail. Actually `if not arr:` returns True for None => returns 0.
        # If you want strict behavior, adjust the function. Current behavior returns 0:
        assert max_subarray_sum(None) == 0

    def test_error_case_non_numeric_elements_in_list(self):
        with pytest.raises(TypeError):
            max_subarray_sum([1, "2", 3])  # current + num will fail

    def test_error_case_iterable_not_list_but_indexable_required(self):
        # The function uses arr[0] and slicing arr[1:], so non-sequence iterables will fail.
        with pytest.raises(TypeError):
            max_subarray_sum(iter([1, 2, 3]))  # iter(...) has no __getitem__/slicing

    def test_error_case_mixed_types_cannot_be_compared_or_added(self):
        with pytest.raises(TypeError):
            max_subarray_sum([1, object(), 2])
